1172					const proxy = rpcProtocol.getProxy(MainContext.MainThreadDocumentDiff);
1173					if (token?.isCancellationRequested) {
1174						const error = new errors.CancellationError();
1175						return {
1176							changes: AsyncIterableObject.EMPTY,
1177							complete: Promise.reject(error),
1178						};
1179					}
1180					const resultPromise = proxy.$computeDocumentDiff(
1181						originalDocument.uri,
1182						modifiedDocument.uri,
1183						options?.ignoreTrimWhitespace ?? false,
1184						options?.maxComputationTimeMs ?? 5000,
1185						options?.computeMoves ?? false,
1186					);
1187					const diffPromise = token ? raceCancellationError(resultPromise, token) : resultPromise;
1188					const mappedPromise = diffPromise.then(result => {
1189						if (!result) {
1190							throw new Error('Could not compute diff. Make sure both documents are available.');
1191						}
1192						return result;
1193					});
1194	
1195					const mapChange = (c: IDocumentDiffLineChangeDto) => ({
1196						originalRange: typeConverters.Range.to(c.originalRange),
1197						modifiedRange: typeConverters.Range.to(c.modifiedRange),
1198						innerChanges: c.innerChanges?.map(ic => ({
1199							originalRange: typeConverters.Range.to(ic.originalRange),
1200							modifiedRange: typeConverters.Range.to(ic.modifiedRange),
1201						})),
1202					});
1203	
1204					// TODO@API currently the diff is computed in one shot and all changes are emitted at once.
1205					// In the future, we may want to stream changes incrementally as they are computed
1206					// (e.g. by having the worker yield partial results).
1207					return {
1208						changes: new AsyncIterableObject<vscode.TextDiffChange>(async emitter => {
1209							const result = await mappedPromise;
1210							emitter.emitMany(result.changes.map(mapChange));
1211						}),
1212						complete: mappedPromise.then(result => ({
1213							identical: result.identical,
1214							mayBeIncomplete: result.quitEarly,
1215							moves: result.moves.map(m => ({
1216								originalRange: typeConverters.Range.to(m.originalRange),
1217								modifiedRange: typeConverters.Range.to(m.modifiedRange),
1218								changes: m.changes.map(mapChange),
1219							})),
1220						})),
1221					};
