python3 << 'EOF'
import re

filepath = "/private/tmp/omniweave-corpus/vscode/src/vs/workbench/api/common/extHost.api.impl.ts"
with open(filepath, 'r') as f:
    lines = f.readlines()

call_lines = []
for i, line in enumerate(lines, 1):
    if 'checkProposedApiEnabled(' in line and 'export function' not in line and 'import' not in line:
        call_lines.append(i)

# More robust: look for the nearest function-opening line above each call
# A function-opening is a line that contains '(' and ends with '{' (method shorthand, getter/setter, arrow function)
# We track indentation level - the enclosing function must be at less indentation than the call

def get_indent(line):
    return len(line) - len(line.lstrip())

func_defs = {}  # line_num -> name
for i, line in enumerate(lines, 1):
    stripped = line.strip()
    indent = get_indent(line)

    # getter/setter
    m = re.match(r'(?:async\s+)?(?:get|set)\s+([\w$]+)\s*\(', stripped)
    if m and (stripped.endswith('{') or stripped.endswith('{')):
        func_defs[i] = f"get/set {m.group(1)}"
        continue

    # method shorthand: name(...) { or name(...): Type {
    m = re.match(r'(?:async\s+)?([\w$]+)\s*(?:<[^>]*>)?\s*\([^)]*\)(?:\s*:\s*[^{]+)?\s*\{', stripped)
    if m and m.group(1) not in ('if', 'for', 'while', 'switch', 'try', 'catch', 'else', 'do', 'return', 'new', 'case', 'const', 'let', 'var', 'class', 'export', 'import', 'throw', 'await', 'typeof', 'Promise', 'Object'):
        func_defs[i] = m.group(1)
        continue

    # Arrow function with name: name: (...) => { or name = (...) => {
    m = re.match(r'([\w$]+)\s*[=:]\s*(?:async\s*)?\(', stripped)
    if m and ('=>' in stripped or 'function' in stripped):
        func_defs[i] = m.group(1)
        continue

    # function keyword
    m = re.match(r'(?:export\s+)?(?:async\s+)?function\s+\*?([\w$]+)\s*\(', stripped)
    if m:
        func_defs[i] = m.group(1)
        continue

caller_map = {}
for call_line in call_lines:
    call_indent = get_indent(lines[call_line - 1])

    # find nearest enclosing function - must have less or equal indentation and be before the call
    best = None
    best_line = 0
    for func_line, name in func_defs.items():
        if func_line < call_line:
            fi = get_indent(lines[func_line - 1])
            if fi < call_indent and func_line > best_line:
                best_line = func_line
                best = name

    caller_map[call_line] = (best, best_line)

# Find distinct callers by (name, start_line) key
distinct = {}
for call_line, (name, start) in sorted(caller_map.items()):
    key = (name, start)
    if key not in distinct:
        distinct[key] = call_line

print(f"Distinct callers in extHost.api.impl.ts: {len(distinct)}")
for (name, start), first_call in sorted(distinct.items(), key=lambda x: x[1]):
    print(f"  line {first_call}: {name} (defined at line {start})")
EOF

